import {
  ChangeDetectionStrategy,
  Component,
  ElementRef,
  afterNextRender,
  computed,
  input,
  signal,
  viewChild,
} from '@angular/core';
import { mergeClasses } from '../../utils/merge-classes';
import {
  separatorLineVariants,
  separatorRootVariants,
  type SeparatorLineVariants,
  type SeparatorRootVariants,
} from './separator.variants';

@Component({
  selector: 'n-separator',
  standalone: true,
  template: `
    <span
      data-slot="line"
      [class]="lineClasses()"
      class="flex-1"
      aria-hidden="true"
    ></span>
    <span
      data-slot="label"
      class="text-xs text-muted-foreground whitespace-nowrap flex items-center"
      [class.px-2]="hasMiddle() && nOrientation() === 'horizontal'"
      [class.py-2]="hasMiddle() && nOrientation() === 'vertical'"
      [hidden]="!hasMiddle()"
    >
      @if (nLabel()) { <span>{{ nLabel() }}</span> }
      <span #contentSlot class="flex items-center"><ng-content /></span>
    </span>
    <span
      data-slot="line"
      [class]="lineClasses()"
      class="flex-1"
      aria-hidden="true"
      [hidden]="!hasMiddle()"
    ></span>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    'data-slot': 'root',
    '[class]': 'rootClasses()',
    '[attr.role]': 'nDecorative() ? "none" : "separator"',
    '[attr.aria-orientation]':
      'nDecorative() ? null : (nOrientation() === "vertical" ? "vertical" : null)',
  },
})
export class SeparatorComponent {
  readonly nOrientation = input<SeparatorLineVariants['nOrientation']>('horizontal');
  readonly nVariant     = input<SeparatorLineVariants['nVariant']>('solid');
  readonly nSize        = input<SeparatorLineVariants['nSize']>('default');
  readonly nIntensity   = input<SeparatorLineVariants['nIntensity']>('default');
  readonly nGradient    = input<boolean>(false);
  readonly nInset       = input<SeparatorRootVariants['nInset']>(false);
  readonly nDecorative  = input<boolean>(false);
  readonly nLabel       = input<string>('');
  readonly nClass       = input<string>('');

  private readonly _contentSlot = viewChild<ElementRef<HTMLElement>>('contentSlot');
  private readonly _hasProjected = signal(false);

  protected readonly hasMiddle = computed(
    () => !!this.nLabel() || this._hasProjected(),
  );

  protected readonly rootClasses = computed(() =>
    mergeClasses(
      separatorRootVariants({ nOrientation: this.nOrientation(), nInset: this.nInset() }),
      this.nClass(),
    ),
  );

  protected readonly lineClasses = computed(() =>
    separatorLineVariants({
      nOrientation: this.nOrientation(),
      nVariant: this.nVariant(),
      nSize: this.nSize(),
      nIntensity: this.nIntensity(),
      nGradient: this.nGradient(),
    }),
  );

  constructor() {
    afterNextRender(() => {
      const el = this._contentSlot()?.nativeElement;
      const has = !!el && (el.childNodes.length > 0 && (el.textContent?.trim().length ?? 0) > 0
        || (el?.childElementCount ?? 0) > 0);
      this._hasProjected.set(has);
    });
  }
}

import { cva, type VariantProps } from 'class-variance-authority';

export const separatorLineVariants = cva(
  'shrink-0',
  {
    variants: {
      nOrientation: {
        horizontal: 'h-px w-full',
        vertical: 'w-px h-full min-h-4',
      },
      nVariant: {
        solid: 'bg-border',
        dashed: 'bg-transparent border-dashed border-border',
        dotted: 'bg-transparent border-dotted border-border',
      },
      nSize: {
        sm: '',
        default: '',
        lg: '',
      },
      nIntensity: {
        default: '',
        muted: 'opacity-50',
        strong: '',
      },
      nGradient: {
        true: 'bg-gradient-to-r from-transparent via-border to-transparent',
        false: '',
      },
    },
    compoundVariants: [
      // thickness × orientation
      { nOrientation: 'horizontal', nSize: 'sm', class: 'h-px' },
      { nOrientation: 'horizontal', nSize: 'default', class: 'h-px' },
      { nOrientation: 'horizontal', nSize: 'lg', class: 'h-0.5' },
      { nOrientation: 'vertical', nSize: 'sm', class: 'w-px' },
      { nOrientation: 'vertical', nSize: 'default', class: 'w-px' },
      { nOrientation: 'vertical', nSize: 'lg', class: 'w-0.5' },
      // dashed/dotted use border instead of bg — strip h/w to border
      { nVariant: 'dashed', nOrientation: 'horizontal', class: 'border-t bg-transparent h-0' },
      { nVariant: 'dotted', nOrientation: 'horizontal', class: 'border-t bg-transparent h-0' },
      { nVariant: 'dashed', nOrientation: 'vertical', class: 'border-l bg-transparent w-0' },
      { nVariant: 'dotted', nOrientation: 'vertical', class: 'border-l bg-transparent w-0' },
      // intensity
      { nVariant: 'solid', nIntensity: 'strong', class: 'bg-foreground/30' },
      { nVariant: 'dashed', nIntensity: 'strong', class: 'border-foreground/30' },
      { nVariant: 'dotted', nIntensity: 'strong', class: 'border-foreground/30' },
      // gradient overrides solid bg
      { nGradient: true, nVariant: 'solid', class: 'bg-gradient-to-r from-transparent via-border to-transparent' },
    ],
    defaultVariants: {
      nOrientation: 'horizontal',
      nVariant: 'solid',
      nSize: 'default',
      nIntensity: 'default',
      nGradient: false,
    },
  },
);

export type SeparatorLineVariants = VariantProps<typeof separatorLineVariants>;

export const separatorRootVariants = cva(
  'flex items-center',
  {
    variants: {
      nOrientation: {
        horizontal: 'w-full flex-row',
        vertical: 'h-full flex-col self-stretch',
      },
      nInset: {
        true: '',
        false: '',
      },
    },
    compoundVariants: [
      { nOrientation: 'horizontal', nInset: true, class: 'my-4' },
      { nOrientation: 'vertical', nInset: true, class: 'mx-4' },
    ],
    defaultVariants: {
      nOrientation: 'horizontal',
      nInset: false,
    },
  },
);

export type SeparatorRootVariants = VariantProps<typeof separatorRootVariants>;

